import{_ as a,c as e,o as r,a4 as h}from"./chunks/framework.nQaBHiNx.js";const b=JSON.parse('{"title":"第九章 数据库技术基础","description":"","frontmatter":{"permalink":"/basic/ruankao/software-designer/08-database.html"},"headers":[],"relativePath":"computer/ruankao/software-designer/09-第九章 数据库技术基础.md","filePath":"computer/ruankao/software-designer/09-第九章 数据库技术基础.md"}'),l={name:"computer/ruankao/software-designer/09-第九章 数据库技术基础.md"},t=h('<h1 id="第九章-数据库技术基础" tabindex="-1">第九章 数据库技术基础 <a class="header-anchor" href="#第九章-数据库技术基础" aria-label="Permalink to &quot;第九章 数据库技术基础&quot;">​</a></h1><p>数据库技术是研究数据库的结构、存储、设计、管理和应用的一门软件学科。数据库系统本质上是一个用计算机存储信息的系统。数据库管理系统是位于用户与操作系统之间的一层数据管理软件，其基本目标是提供一个可以方便、有效地存储数据库信息的环境。</p><h2 id="_9-1-基本概念" tabindex="-1">9.1 基本概念 <a class="header-anchor" href="#_9-1-基本概念" aria-label="Permalink to &quot;9.1 基本概念&quot;">​</a></h2><h3 id="_9-1-1-数据库与数据库系统" tabindex="-1">9.1.1 数据库与数据库系统 <a class="header-anchor" href="#_9-1-1-数据库与数据库系统" aria-label="Permalink to &quot;9.1.1 数据库与数据库系统&quot;">​</a></h3><p>数据是描述事物的符号记录，它具有多种表现形式，可以是文字、图形、图像、声音和语言等。</p><p>信息是现实世界事物的存在方式或状态的反映。</p><p>数据库系统是一个采用了数据库技术，有组织地、动态地存储大量相关数据，方便多用户访问的计算机系统。</p><h3 id="_9-1-2-数据库管理系统的功能" tabindex="-1">9.1.2 数据库管理系统的功能 <a class="header-anchor" href="#_9-1-2-数据库管理系统的功能" aria-label="Permalink to &quot;9.1.2 数据库管理系统的功能&quot;">​</a></h3><p>数据库管理系统主要实现对共享数据有效地组织、管理和存取，故 DBMS 应具有一下六个方面的功能。</p><ol><li>数据定义</li><li>数据库操作</li><li>数据库运行管理</li><li>数据的组织、存储和管理</li><li>数据库的建立和维护</li><li>其他功能</li></ol><h3 id="_9-1-3-数据库管理系统的特征及分类" tabindex="-1">9.1.3 数据库管理系统的特征及分类 <a class="header-anchor" href="#_9-1-3-数据库管理系统的特征及分类" aria-label="Permalink to &quot;9.1.3 数据库管理系统的特征及分类&quot;">​</a></h3><h3 id="_9-1-4-数据库系统的体系结构" tabindex="-1">9.1.4 数据库系统的体系结构 <a class="header-anchor" href="#_9-1-4-数据库系统的体系结构" aria-label="Permalink to &quot;9.1.4 数据库系统的体系结构&quot;">​</a></h3><h3 id="_9-1-5-数据库的三级模式结构" tabindex="-1">9.1.5 数据库的三级模式结构 <a class="header-anchor" href="#_9-1-5-数据库的三级模式结构" aria-label="Permalink to &quot;9.1.5 数据库的三级模式结构&quot;">​</a></h3><h3 id="_9-1-6-大数据" tabindex="-1">9.1.6 大数据 <a class="header-anchor" href="#_9-1-6-大数据" aria-label="Permalink to &quot;9.1.6 大数据&quot;">​</a></h3><h2 id="_9-2-数据模型" tabindex="-1">9.2 数据模型 <a class="header-anchor" href="#_9-2-数据模型" aria-label="Permalink to &quot;9.2 数据模型&quot;">​</a></h2><h3 id="_9-2-1-基本概念" tabindex="-1">9.2.1 基本概念 <a class="header-anchor" href="#_9-2-1-基本概念" aria-label="Permalink to &quot;9.2.1 基本概念&quot;">​</a></h3><h3 id="_9-2-2-数据模型的三要素" tabindex="-1">9.2.2 数据模型的三要素 <a class="header-anchor" href="#_9-2-2-数据模型的三要素" aria-label="Permalink to &quot;9.2.2 数据模型的三要素&quot;">​</a></h3><h3 id="_9-2-3-e-r-模型" tabindex="-1">9.2.3 E-R 模型 <a class="header-anchor" href="#_9-2-3-e-r-模型" aria-label="Permalink to &quot;9.2.3 E-R 模型&quot;">​</a></h3><h3 id="_9-2-4-数据模型" tabindex="-1">9.2.4 数据模型 <a class="header-anchor" href="#_9-2-4-数据模型" aria-label="Permalink to &quot;9.2.4 数据模型&quot;">​</a></h3><h3 id="_9-2-5-关系模型" tabindex="-1">9.2.5 关系模型 <a class="header-anchor" href="#_9-2-5-关系模型" aria-label="Permalink to &quot;9.2.5 关系模型&quot;">​</a></h3><h2 id="_9-3-关系代数" tabindex="-1">9.3 关系代数 <a class="header-anchor" href="#_9-3-关系代数" aria-label="Permalink to &quot;9.3 关系代数&quot;">​</a></h2><h3 id="_9-3-1-关系数据库的基本概念" tabindex="-1">9.3.1 关系数据库的基本概念 <a class="header-anchor" href="#_9-3-1-关系数据库的基本概念" aria-label="Permalink to &quot;9.3.1 关系数据库的基本概念&quot;">​</a></h3><h3 id="_9-3-2-5-种基本的关系代数运算" tabindex="-1">9.3.2 5 种基本的关系代数运算 <a class="header-anchor" href="#_9-3-2-5-种基本的关系代数运算" aria-label="Permalink to &quot;9.3.2 5 种基本的关系代数运算&quot;">​</a></h3><h3 id="_9-3-3-扩展的关系代数运算" tabindex="-1">9.3.3 扩展的关系代数运算 <a class="header-anchor" href="#_9-3-3-扩展的关系代数运算" aria-label="Permalink to &quot;9.3.3 扩展的关系代数运算&quot;">​</a></h3><h2 id="_9-4-关系数据库-sql-语言简洁" tabindex="-1">9.4 关系数据库 SQL 语言简洁 <a class="header-anchor" href="#_9-4-关系数据库-sql-语言简洁" aria-label="Permalink to &quot;9.4 关系数据库 SQL 语言简洁&quot;">​</a></h2><h3 id="_9-4-1-sql-数据库体系组成" tabindex="-1">9.4.1 SQL 数据库体系组成 <a class="header-anchor" href="#_9-4-1-sql-数据库体系组成" aria-label="Permalink to &quot;9.4.1 SQL 数据库体系组成&quot;">​</a></h3><h3 id="_9-4-2-sql-的基本组成" tabindex="-1">9.4.2 SQL 的基本组成 <a class="header-anchor" href="#_9-4-2-sql-的基本组成" aria-label="Permalink to &quot;9.4.2 SQL 的基本组成&quot;">​</a></h3><h3 id="_9-4-3-sql-数据定义" tabindex="-1">9.4.3 SQL 数据定义 <a class="header-anchor" href="#_9-4-3-sql-数据定义" aria-label="Permalink to &quot;9.4.3 SQL 数据定义&quot;">​</a></h3><h3 id="_9-4-4-sql-数据查询" tabindex="-1">9.4.4 SQL 数据查询 <a class="header-anchor" href="#_9-4-4-sql-数据查询" aria-label="Permalink to &quot;9.4.4 SQL 数据查询&quot;">​</a></h3><h3 id="_9-4-5-sql-数据更新" tabindex="-1">9.4.5 SQL 数据更新 <a class="header-anchor" href="#_9-4-5-sql-数据更新" aria-label="Permalink to &quot;9.4.5 SQL 数据更新&quot;">​</a></h3><h3 id="_9-4-6-sql-访问控制" tabindex="-1">9.4.6 SQL 访问控制 <a class="header-anchor" href="#_9-4-6-sql-访问控制" aria-label="Permalink to &quot;9.4.6 SQL 访问控制&quot;">​</a></h3><h3 id="_9-4-7-嵌入式-sql" tabindex="-1">9.4.7 嵌入式 SQL <a class="header-anchor" href="#_9-4-7-嵌入式-sql" aria-label="Permalink to &quot;9.4.7 嵌入式 SQL&quot;">​</a></h3><h2 id="_9-5-关系数据库的规范化" tabindex="-1">9.5 关系数据库的规范化 <a class="header-anchor" href="#_9-5-关系数据库的规范化" aria-label="Permalink to &quot;9.5 关系数据库的规范化&quot;">​</a></h2><h3 id="_9-5-1-函数依赖" tabindex="-1">9.5.1 函数依赖 <a class="header-anchor" href="#_9-5-1-函数依赖" aria-label="Permalink to &quot;9.5.1 函数依赖&quot;">​</a></h3><h3 id="_9-5-2-规范化" tabindex="-1">9.5.2 规范化 <a class="header-anchor" href="#_9-5-2-规范化" aria-label="Permalink to &quot;9.5.2 规范化&quot;">​</a></h3><h3 id="_9-5-3-模式分解及分解应具有的特性" tabindex="-1">9.5.3 模式分解及分解应具有的特性 <a class="header-anchor" href="#_9-5-3-模式分解及分解应具有的特性" aria-label="Permalink to &quot;9.5.3 模式分解及分解应具有的特性&quot;">​</a></h3><h2 id="_9-6-数据库的控制功能" tabindex="-1">9.6 数据库的控制功能 <a class="header-anchor" href="#_9-6-数据库的控制功能" aria-label="Permalink to &quot;9.6 数据库的控制功能&quot;">​</a></h2><h3 id="_9-6-1-事务管理" tabindex="-1">9.6.1 事务管理 <a class="header-anchor" href="#_9-6-1-事务管理" aria-label="Permalink to &quot;9.6.1 事务管理&quot;">​</a></h3><h3 id="_9-6-2-数据库的备份与回复" tabindex="-1">9.6.2 数据库的备份与回复 <a class="header-anchor" href="#_9-6-2-数据库的备份与回复" aria-label="Permalink to &quot;9.6.2 数据库的备份与回复&quot;">​</a></h3><h3 id="_9-6-3-并发控制" tabindex="-1">9.6.3 并发控制 <a class="header-anchor" href="#_9-6-3-并发控制" aria-label="Permalink to &quot;9.6.3 并发控制&quot;">​</a></h3>',40),o=[t];function i(n,d,s,_,c,q){return r(),e("div",null,o)}const m=a(l,[["render",i]]);export{b as __pageData,m as default};
